<template>
 <el-card class="page-card config-card"><template #header><div class="title">系统基础配置</div></template><el-form label-width="110px" style="max-width:650px"><el-form-item label="系统名称"><el-input v-model="form.systemName" maxlength="50" show-word-limit/></el-form-item><el-form-item label="系统 Logo"><div class="logo-editor"><div class="preview"><img v-if="form.systemLogo" :src="form.systemLogo"/><span v-else>≋</span></div><div><el-upload :show-file-list="false" :before-upload="upload"><el-button type="primary" plain>上传图片</el-button></el-upload><p>支持 JPG、PNG、SVG，文件不超过 2MB</p></div></div></el-form-item><el-form-item><el-button type="primary" :loading="saving" @click="save">保存配置</el-button><el-button @click="load">恢复</el-button></el-form-item></el-form></el-card>
</template>
<script setup lang="ts">import {onMounted,reactive,ref} from 'vue';import {ElMessage} from 'element-plus';import {getConfig,updateConfig,uploadLogo} from '@/api/system';import {appStore} from '@/store/app';const form=reactive({systemName:'',systemLogo:''}),saving=ref(false);const load=async()=>Object.assign(form,await getConfig());const upload=async(file:File)=>{if(file.size>2*1024*1024){ElMessage.error('文件不能超过 2MB');return false}const d=await uploadLogo(file);form.systemLogo=d.fileUrl;ElMessage.success('上传成功，请保存配置');return false};const save=async()=>{if(!form.systemName.trim())return ElMessage.warning('系统名称不能为空');saving.value=true;try{await updateConfig(form);appStore.systemName=form.systemName;appStore.systemLogo=form.systemLogo;ElMessage.success('配置已保存')}finally{saving.value=false}};onMounted(load)</script>
<style scoped>.config-card{min-height:420px}.title{font-weight:700}.logo-editor{display:flex;align-items:center;gap:18px}.preview{width:96px;height:96px;border:1px dashed #a9bfd1;border-radius:14px;display:grid;place-items:center;overflow:hidden;background:#f5faff;color:#178ee4;font-size:64px;font-weight:900}.preview img{width:100%;height:100%;object-fit:contain}.logo-editor p{margin:8px 0 0;color:#95a3af;font-size:12px}</style>
